import React, { forwardRef } from 'react';
import { cx } from 'emotion';

import { type CommonProps } from '@contentful/f36-core';
import { Image, type ImageProps } from '@contentful/f36-image';
import {
  Tooltip,
  type TooltipInternalProps,
  type WithEnhancedContent,
} from '@contentful/f36-tooltip';

import { getAvatarStyles } from './Avatar.styles';
import { type ColorVariant, type Size, type SizeInPixel } from './utils';
import type { Variant } from './types';
export { type Variant } from './types';

export interface AvatarProps extends CommonProps {
  alt?: ImageProps['alt'];
  /**
   * @default false
   */
  isLoading?: boolean;
  /**
   * Use the available sizes or a numerical custom one, e.g. '52px'
   * @default 'medium'
   */
  size?: Size | SizeInPixel;
  initials?: string;
  src?: ImageProps['src'];
  /**
   * A tooltipProps attribute used to conditionally render the tooltip around root element
   */
  tooltipProps?: CommonProps &
    WithEnhancedContent &
    Omit<TooltipInternalProps, 'children'>;
  /**
   * @default 'user'
   */
  variant?: Variant;
  /**
   * @default 'gray'
   */
  colorVariant?: ColorVariant;
  icon?: React.ReactElement;
}

function _Avatar(
  {
    alt = '',
    className,
    colorVariant = 'gray',
    icon,
    isLoading = false,
    size = 'medium',
    initials,
    src,
    testId = 'cf-ui-avatar',
    tooltipProps,
    variant = 'user',
    ...otherProps
  }: AvatarProps,
  forwardedRef: React.Ref<HTMLDivElement>,
) {
  // Only render the fallback when `src` is undefined or an empty string
  const isFallback = Boolean(!isLoading && !src);
  const styles = getAvatarStyles({ size, variant, colorVariant });

  const content = (
    <div
      className={cx(styles.root, className, {
        [styles.imageContainer]: !!src,
      })}
      data-test-id={testId}
      ref={forwardedRef}
      {...otherProps}
    >
      {isFallback ? (
        <div className={styles.fallback} data-test-id={`${testId}-fallback`}>
          {initials?.substring(0, 2).toUpperCase()}
        </div>
      ) : (
        <Image
          alt={alt}
          className={styles.image}
          src={src}
          height="100%"
          width="100%"
        />
      )}
      {!!icon && (
        <span className={styles.overlayIcon} data-test-id={`${testId}-icon`}>
          {icon}
        </span>
      )}
    </div>
  );

  if (tooltipProps)
    return (
      <Tooltip {...tooltipProps} usePortal>
        {content}
      </Tooltip>
    );

  return content;
}

export const Avatar = forwardRef(_Avatar);
import { css } from 'emotion';
import tokens from '@contentful/f36-tokens';
import { type AvatarProps } from './Avatar';
import { type Variant } from './types';
import {
  applyMuted,
  avatarColorMap,
  getColorWidth,
  getInnerRadius,
  getOuterRadius,
  getTotalBorderWidth,
  parseSize,
  toPixels,
  type ColorVariant,
} from './utils';

export const getColorVariantStyles = (
  variant: Variant,
  colorVariant: ColorVariant,
  size: number,
) => {
  const colorToken: string = avatarColorMap[colorVariant];

  const colorWidth = getColorWidth(colorVariant);
  const totalBorderWidth = getTotalBorderWidth(variant, colorVariant, size);

  return {
    boxShadow: [
      `0px 0px 0px ${colorWidth}px ${colorToken} inset`,
      `0px 0px 0px ${totalBorderWidth}px ${tokens.colorWhite} inset`,
    ].join(', '),
  };
};

const getInitialsFontSize = (size: number) => Math.round(size / 2);

export const getAvatarStyles = ({
  size: sizeOption,
  variant,
  colorVariant,
}: {
  size: AvatarProps['size'];
  variant: Variant;
  colorVariant: ColorVariant;
}) => {
  const borderRadius = getOuterRadius(variant);
  const innerBorderRadius = getInnerRadius(variant);

  const size = parseSize(sizeOption);
  const totalBorderWidth = getTotalBorderWidth(variant, colorVariant, size);

  const isMuted = colorVariant === 'muted';

  return {
    fallback: css({
      backgroundColor: isMuted ? applyMuted(tokens.gray300) : tokens.gray300,
      color: isMuted ? applyMuted(tokens.gray700) : tokens.gray700,
      height: '100%',
      width: '100%',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      fontStretch: 'semi-condensed',
      fontSize: toPixels(getInitialsFontSize(size)),
    }),
    image: css({
      borderRadius: innerBorderRadius,
      display: 'block',

      // loading skeleton
      '& + svg': {
        borderRadius: innerBorderRadius,
        rect: { rx: 0, ry: 0 }, // has a default 4px border radius
      },
    }),
    root: css({
      borderRadius,
      height: size,
      width: size,
      overflow: 'hidden',
      position: 'relative',
      padding: totalBorderWidth,

      // color variant border
      '&::after': {
        borderRadius,
        bottom: 0,
        content: '""',
        display: 'block',
        left: 0,
        position: 'absolute',
        top: 0,
        right: 0,
        ...getColorVariantStyles(variant, colorVariant, size),
      },
    }),
    imageContainer: css(
      {
        backgroundColor: tokens.colorWhite,
        overflow: 'visible',
        zIndex: 1,
      },
      colorVariant === 'muted' && {
        img: {
          opacity: 0.5,
        },
      },
    ),
    overlayIcon: css({
      svg: {
        backgroundColor: tokens.colorWhite,
        borderRadius: '100%',
        position: 'absolute',
        bottom: 0,
        right: '-10%',
        width: '40%',
        height: '40%',
        zIndex: 1,
      },
    }),
  };
};
import tokens from '@contentful/f36-tokens';

import { AvatarProps } from './Avatar';
import { type Variant } from './types';

export const SIZES = ['tiny', 'small', 'medium', 'large'] as const;
export type Size = (typeof SIZES)[number];
export type SizeInPixel = `${number}px`;

export type ColorVariant = keyof typeof avatarColorMap;

export const avatarColorMap = {
  primary: tokens.blue500,
  muted: applyMuted(tokens.gray500),
  green: tokens.green400,
  orange: tokens.orange400,
  yellow: tokens.yellow500,
  purple: tokens.purple400,
  gray: tokens.gray500,
  pink: '#FF77AE',
  emerald: '#00B8A2',
  lavender: '#9095FF',
};

/**
 * @param color Color string in hex format with a leading `#`
 */
export function applyMuted(color: string): string {
  // This is a temporary solution because `color-mix` is not supported in Safari
  const r = parseInt(color.slice(1, 3), 16);
  const g = parseInt(color.slice(3, 5), 16);
  const b = parseInt(color.slice(5, 7), 16);

  return `rgb(${[
    Math.round((255 + r) / 2),
    Math.round((255 + g) / 2),
    Math.round((255 + b) / 2),
  ].join(' ')})`;

  // Eventually we should use `color-mix`
  // return `color-mix(in srgb, ${color}, ${tokens.colorWhite} 50%)`;
}

export function getWhiteBorderWidth(variant: Variant, size: number): number {
  if (variant === 'user') {
    return 1;
  }

  return size >= 48 ? 3 : 2;
}

export function getColorWidth(colorVariant: ColorVariant): number {
  return ['muted', 'gray'].includes(colorVariant) ? 1 : 2;
}

export function getTotalBorderWidth(
  variant: Variant,
  colorVariant: ColorVariant,
  size: number,
): number {
  return getColorWidth(colorVariant) + getWhiteBorderWidth(variant, size);
}

/**
 * Converts the variant size to pixels
 *
 * @param size
 * @returns the size in pixels
 */
export const parseSize = (size: AvatarProps['size']): number => {
  const sizeMap = {
    tiny: 20,
    small: 24,
    medium: 32,
    large: 48,
  };

  return sizeMap[size] ?? parseInt(size.slice(0, -2), 10);
};

/**
 *
 * @param size
 * @returns the size in pixels with the 'px' suffix
 */
export function toPixels(size: number): SizeInPixel {
  return `${size}px`;
}

export function getOuterRadius(variant: Variant): string {
  return variant === 'app' ? '4px' : '100%';
}

export function getInnerRadius(variant: Variant): string {
  return variant === 'app' ? '1px' : '100%';
}
import React, { forwardRef } from 'react';
import { cx } from 'emotion';

import { Stack, type CommonProps } from '@contentful/f36-core';
import { Menu } from '@contentful/f36-menu';

import { type AvatarProps } from '../Avatar';
import { getAvatarGroupStyles } from './AvatarGroup.styles';

export interface AvatarGroupProps extends CommonProps {
  children?:
    | React.ReactElement<AvatarProps>[]
    | React.ReactElement<AvatarProps>;
  maxVisibleChildren?: number;
  size?: 'small' | 'medium';
  variant?: 'stacked' | 'spaced';
}

function _AvatarGroup(
  {
    children,
    className,
    maxVisibleChildren = 3,
    size = 'medium',
    testId = 'cf-ui-avatar-group',
    variant = 'spaced',
  }: AvatarGroupProps,
  forwardedRef: React.Ref<HTMLDivElement>,
) {
  const styles = getAvatarGroupStyles(size);

  const childrenArray = React.Children.toArray(children);
  const childrenToRenderCount =
    childrenArray.length > maxVisibleChildren
      ? maxVisibleChildren - 1
      : maxVisibleChildren;
  const childrenToRender = childrenArray.slice(0, childrenToRenderCount);
  const childrenInMenu = childrenArray.slice(childrenToRenderCount);

  return (
    <Stack
      flexDirection="row"
      testId={testId}
      ref={forwardedRef}
      className={cx(className, {
        [styles.groupStacked]: variant === 'stacked',
        [styles.groupSpaced]: variant === 'spaced',
      })}
    >
      {childrenToRender.map((child, index) => {
        const zIndex = childrenToRender.length - index;

        return React.cloneElement(child as React.ReactElement, {
          key: `avatar-rendered-${index}`,
          size: size,
          className: cx((child as React.ReactElement).props.className, {
            [styles.avatarStacked]: variant === 'stacked',
          }),
          style: {
            zIndex,
          },
        });
      })}
      {childrenInMenu.length > 0 && (
        <Menu placement="bottom-end">
          <Menu.Trigger>
            <button
              type="button"
              className={cx(
                {
                  [styles.avatarStacked]: variant === 'stacked',
                },
                styles.moreAvatarsBtn,
              )}
            >
              +{childrenInMenu.length}
            </button>
          </Menu.Trigger>
          <Menu.List>
            {childrenInMenu.map((child, index) => {
              return (
                <Menu.Item
                  className={styles.moreAvatarsItem}
                  key={`avatar-${index}`}
                >
                  {React.cloneElement(child as React.ReactElement, {
                    key: `avatar-menuitem-${index}`,
                    size: 'tiny',
                    tooltipProps: undefined,
                  })}
                  {(child as React.ReactElement).props.alt}
                </Menu.Item>
              );
            })}
          </Menu.List>
        </Menu>
      )}
    </Stack>
  );
}
export const AvatarGroup = forwardRef(_AvatarGroup);
import { css } from 'emotion';
import tokens from '@contentful/f36-tokens';
import { type AvatarProps } from '../Avatar/';
import { parseSize, toPixels } from '../Avatar/utils';

export const getAvatarGroupStyles = (size: AvatarProps['size']) => {
  return {
    groupSpaced: css({
      gap: tokens.spacing2Xs,
    }),
    groupStacked: css({
      gap: 0,
      '> :not(:first-child)': {
        marginLeft: `-${tokens.spacing2Xs}`,
      },
    }),
    avatarStacked: css({
      position: 'relative',
      boxShadow: `0px 0px 0px 1px ${tokens.colorWhite}`,
    }),
    moreAvatarsBtn: css({
      cursor: 'pointer',
      backgroundColor: tokens.colorWhite,
      color: tokens.gray600,
      fontSize: tokens.fontSizeS,
      border: 'none',
      boxShadow: `0px 0px 0px 1px ${tokens.gray200} inset`,
      borderRadius: '99999999em',
      height: toPixels(parseSize(size)),
      width: toPixels(parseSize(size)),
      overflow: 'hidden',
      zIndex: 0,
    }),
    moreAvatarsItem: css({
      cursor: 'default',
    }),
  };
};
